import{_ as i,o as a,c as e,ag as o}from"./chunks/framework.DXGyWiRo.js";const p=JSON.parse('{"title":"讯飞带屏音箱用户协议","description":"","frontmatter":{"title":"讯飞带屏音箱用户协议"},"headers":[],"relativePath":"legal/xfyun-speaker-tos.md","filePath":"legal/xfyun-speaker-tos.md","lastUpdated":null}'),r={name:"legal/xfyun-speaker-tos.md"};function t(h,l,n,s,d,c){return a(),e("div",null,[...l[0]||(l[0]=[o('<p>欢迎使用讯飞带屏音箱应用软件及服务。</p><p>为使用讯飞带屏音箱应用软件（以下简称“讯飞带屏音箱”）及服务，科大讯飞股份有限公司以及其关联公司（以下简称“科大讯飞”）与你（以下称“用户”）就讯飞带屏音箱的使用等相关事项订立以下协议。该协议于2022年12月13日发布，自讯飞带屏音箱用户注册成功时生效。</p><p><strong>你通过网络页面点击确认或以其他方式选择接受本协议和使用讯飞带屏音箱的服务，即表示同意并接受本协议条款，请你审慎阅读，并充分理解本协议的全部内容。</strong></p><h2 id="服务条款的范围" tabindex="-1">服务条款的范围 <a class="header-anchor" href="#服务条款的范围" aria-label="Permalink to &quot;服务条款的范围&quot;">​</a></h2><ol><li>协议使用主体范围 本协议是你与科大讯飞股份有限公司之间关于你下载、安装、使用本软件，以及使用讯飞带屏音箱相关服务所订立的协议。</li><li>协议关系 本协议中“用户”是指注册、登录、使用讯飞带屏音箱服务的个人或组织。 若你未满18周岁，请在法定监护人的陪同下阅读本协议，并特别注意未成年人使用条款。</li></ol><h2 id="账号注册与认证" tabindex="-1">账号注册与认证 <a class="header-anchor" href="#账号注册与认证" aria-label="Permalink to &quot;账号注册与认证&quot;">​</a></h2><ol><li>你使用本服务前需要注册一个讯飞带屏音箱的服务账号，讯飞带屏音箱账号可以通过手机号码来进行验证和绑定。讯飞带屏音箱有权根据用户需求或产品需要对帐号注册和绑定的方式进行变更。</li><li>用户在注册讯飞带屏音箱账号时承诺遵守法律法规、社会主义制度、国家利益、公民合法权益、公共秩序、社会道德风尚和信息真实性等底线，不得在注册资料中出现违法和不良信息，且用户保证其在注册和使用账号时，不得有以下情形：</li></ol><ul><li>违反宪法或法律法规规定的；</li><li>危害国家安全，泄露国家秘密，颠覆国家政权破坏国家统一的；</li><li>损害国家荣誉和利益的，损害公共利益的；</li><li>煽动民族仇恨、民族歧视，破坏民族团结的；</li><li>破坏国家宗教政策，宣扬邪教和封建迷信的；</li><li>散布谣言，扰乱社会秩序，破坏社会稳定的；</li><li>散布淫秽、色情、赌博、暴力、凶杀、恐怖或者教唆犯罪的；</li><li>侮辱或者诽谤他人，侵害他人合法权益的；</li><li>含有法律、行政法规禁止的其他内容的。</li></ul><p>若用户提供的账号注册资料不准确、不真实、含有违法或不良信息的，将不予进行注册，并保留终止用户使用讯飞带屏音箱各项服务的权利。若用户以虚假信息骗取账号注册或账号头像、个人简介等注册资料存在违法和不良信息的，科大讯飞股份有限公司有权采取通知限期改正、暂停使用、注销登记等措施。对于冒用关联机构或社会名人注册账号名称的，科大讯飞股份有限公司有权注销该账号，并向政府主管部门进行报告。</p><h2 id="隐私政策" tabindex="-1">隐私政策 <a class="header-anchor" href="#隐私政策" aria-label="Permalink to &quot;隐私政策&quot;">​</a></h2><p>讯飞带屏音箱尊重并保护所有使用服务用户的个人隐私权。为了给您提供更准确、更有个性化的服务，讯飞带屏音箱会按照本隐私权政策的规定使用和披露您的个人信息。但讯飞带屏音箱将以高度的勤勉、审慎义务对待这些信息。除本隐私权政策另有规定外，在未征得您事先许可的情况下 ，讯飞带屏音箱不会将这些信息对外披露或向第三方提供。讯飞带屏音箱会不时更新本隐私权政策，更新时将会通过弹窗的形式通知您。</p><p>您在同意讯飞带屏音箱服务使用协议之时，即视为您已经同意本隐私权政策全部内容。本隐私权政策属于讯飞带屏音箱服务使用协议不可分割的一部分。</p><h4 id="适用范围" tabindex="-1">适用范围 <a class="header-anchor" href="#适用范围" aria-label="Permalink to &quot;适用范围&quot;">​</a></h4><ol><li>在您注册讯飞带屏音箱帐号时，您根据讯飞带屏音箱要求提供的个人注册信息；</li><li>在您使用讯飞带屏音箱网络服务时，讯飞带屏音箱自动接收并记录的您的浏览器信息，包括但不限于您的IP地址、浏览器的类型、使用的语言、访问日期和时间、软硬件特征信息及您需求的网页记录等数据；</li><li>讯飞带屏音箱通过合法途径从商业伙伴处取得的用户个人数据；</li><li>您在讯飞带屏音箱中添加绑定的设备信息。</li></ol><p>您了解并同意，以下信息不适用本隐私权政策：</p><ol><li>您在使用讯飞带屏音箱提供的搜索服务时输入的关键字信息；</li><li>您在使用讯飞带屏音箱提供的服务时的行为信息；</li><li>讯飞带屏音箱收集到的您在讯飞带屏音箱发布的有关信息数据，包括但不限于参与活动、成交信息及评价详情；</li><li>违反法律规定或违反讯飞带屏音箱规则行为及讯飞带屏音箱已对您采取的措施。</li></ol><h4 id="信息使用" tabindex="-1">信息使用 <a class="header-anchor" href="#信息使用" aria-label="Permalink to &quot;信息使用&quot;">​</a></h4><ol><li>讯飞带屏音箱不会向任何无关第三方提供、出售、出租、分享或交易您的个人信息，除非事先得到您的许可，或该第三方和讯飞带屏音箱（含讯飞带屏音箱关联公司）单独或共同为您提供服务 ，且在该服务结束后，其将被禁止访问包括其以前能够访问的所有这些资料。</li><li>讯飞带屏音箱亦不允许任何第三方以任何手段收集、编辑、出售或者无偿传播您的个人信息。 任何讯飞带屏音箱平台用户如从事上述活动，一经发现，讯飞带屏音箱有权立即终止与该用户的服务协议。</li><li>为服务用户的目的，讯飞带屏音箱可能通过使用您的个人信息，向您提供您感兴趣的信息，包括但不限于向您发出产品和服务信息，或者与讯飞带屏音箱合作伙伴共享信息以便他们向您发送有关其产品和服务的信息（后者需要您的事先同意）。</li></ol><h4 id="信息披露" tabindex="-1">信息披露 <a class="header-anchor" href="#信息披露" aria-label="Permalink to &quot;信息披露&quot;">​</a></h4><p>在如下情况下，讯飞带屏音箱将依据您的个人意愿或法律的规定全部或部分的披露您的个人信息：</p><ol><li>经您事先同意，向第三方披露；</li><li>为提供您所要求的产品和服务，而必须和第三方分享您的个人信息；</li><li>根据法律的有关规定，或者行政或司法机构的要求，向第三方或者行政、司法机构披露；</li><li>如您出现违反中国有关法律、法规或者讯飞带屏音箱服务协议或相关规则的情况，需要向第三方披露；</li><li>如您是适格的知识产权投诉人并已提起投诉，应被投诉人要求，向被投诉人披露，以便双方处理可能的权利纠纷；</li><li>在讯飞带屏音箱平台上创建的某一交易中，如交易任何一方履行或部分履行了交易义务并提出信息披露请求的，讯飞带屏音箱有权决定向该用户提供其交易对方的联络方式等必要信息，以促成交易的完成或纠纷的解决。</li><li>其它讯飞带屏音箱根据法律、法规或者网站政策认为合适的披露。</li></ol><h4 id="信息存储和交换" tabindex="-1">信息存储和交换 <a class="header-anchor" href="#信息存储和交换" aria-label="Permalink to &quot;信息存储和交换&quot;">​</a></h4><ol><li>讯飞带屏音箱收集的有关您的信息和资料将保存在讯飞带屏音箱及（或）其关联公司的服务器上，这些信息和资料可能传送至您所在国家、地区或讯飞带屏音箱收集信息和资料所在地的境外并在境外被访问、存储和展示。</li><li>您可以在使用讯飞带屏音箱的过程中，随时查看、更正和删除您的个人信息和资料。您的信息和资料存储时间为一年，超时后我们将对您的信息进行匿名处理。</li><li>若您需要注销讯飞带屏音箱账号，清楚您的所有信息和资料，请联系讯飞带屏音箱客服。联系电话：(020)-87001031。</li></ol><h4 id="cookie的使用" tabindex="-1">Cookie的使用 <a class="header-anchor" href="#cookie的使用" aria-label="Permalink to &quot;Cookie的使用&quot;">​</a></h4><ol><li>在您未拒绝接受cookies的情况下，讯飞带屏音箱会在您的设备上设定或取用cookies ，以便您能登录或使用依赖于cookies的讯飞带屏音箱平台服务或功能。讯飞带屏音箱使用cookies可为您提供更加周到的个性化服务，包括推广服务。</li><li>您有权选择接受或拒绝接受cookies。 您可以通过修改浏览器设置的方式拒绝接受cookies。但如果您选择拒绝接受cookies，则您可能无法登录或使用依赖于cookies的讯飞带屏音箱网络服务或功能。</li><li>通过讯飞带屏音箱所设cookies所取得的有关信息，将适用本政策。</li></ol><h4 id="信息安全" tabindex="-1">信息安全 <a class="header-anchor" href="#信息安全" aria-label="Permalink to &quot;信息安全&quot;">​</a></h4><ol><li>讯飞带屏音箱帐号均有安全保护功能，请妥善保管您的用户名及密码信息。讯飞带屏音箱将通过对用户密码进行加密等安全措施确保您的信息不丢失，不被滥用和变造。尽管有前述安全措施 ，但同时也请您注意在信息网络上不存在“完善的安全措施”。</li><li>在使用讯飞带屏音箱网络服务进行网上交易时，您不可避免的要向交易对方或潜在的交易对方披露自己的个人信息，如联络方式或者邮政地址。请您妥善保护自己的个人信息，不要轻易向他人提供。如您发现自己的个人信息泄密，尤其是讯飞带屏音箱用户名及密码发生泄露，请您立即联络讯飞带屏音箱客服，以便讯飞带屏音箱服务团队采取相应措施。联系电话：(020)-87001031。</li></ol><h2 id="用户个人信息的保护" tabindex="-1">用户个人信息的保护 <a class="header-anchor" href="#用户个人信息的保护" aria-label="Permalink to &quot;用户个人信息的保护&quot;">​</a></h2><ol><li>保护用户个人信息是科大讯飞股份有限公司的一项基本原则，科大讯飞将会采取合理的措施保护用户个人信息，除法律法规规定的情形外，未经用户允许科大讯飞不会向第三方公开，透露用户的个人信息。科大讯飞对相关信息采用专业的加密存储与传输方式，保障用户的个人信息安全。</li><li>用户在注册账号和使用本服务的过程中，需要提供一些必要的信息，例如:为向你提供账号注册服务和进行用户身份识别，需要你填写手机号码，手机通讯录匹配功能需要你授权访问手机通讯录等。若国家法律法规或政策有特殊规定的，你需要提供真实的身份信息。若你提供的信息不完整，则无法使用本服务或在使用过程中受到限制。</li><li>一般情况下，你可以随时浏览，修改自己提交的信息，但出于安全性和身份识别（如号码申诉服务）的考虑，你可能无法修改注册时提供的初始注册信息及其他验证信息。</li><li>科大讯飞将运用各种安全技术和程序建立完善的管理制度来保护你的个人信息，以免遭受未经授权的访问、使用或披露。</li><li>未经你的同意，科大讯飞不会向其他任何公司、组织和个人披露你的信息，但法律法规另有规定的除外。</li><li>科大讯飞也保证在你在不希望继续被获取某些数据时，可以关闭获取权限。</li></ol><h2 id="风险及免责" tabindex="-1">风险及免责 <a class="header-anchor" href="#风险及免责" aria-label="Permalink to &quot;风险及免责&quot;">​</a></h2><ol><li>用户必须为自己注册帐户下的一切行为负责，包括你所发表内容的真实性、合法性、准确性、有效性，以及承担因服务使用行为产生的结果。用户应对讯飞带屏音箱服务中的内容自行加以判断，并承担因使用内容而引起的所有风险，包括因对内容真实性、合法性、准确性、有效性的依赖而产生的风险。 如果你发现任何人违反本协议规定或以其他不当的方式使用讯飞带屏音箱服务，请立即向科大讯飞股份有限公司举报或投诉，我们将依法进行处理。</li><li>用户理解并同意，因业务发展需要，科大讯飞保留单方面对本服务的全部或部分服务内容在任何时候不经任何通知的情况下变更、暂停、限制、终止或撤销的权利，用户需承担此风险。</li></ol><h2 id="法律责任" tabindex="-1">法律责任 <a class="header-anchor" href="#法律责任" aria-label="Permalink to &quot;法律责任&quot;">​</a></h2><h4 id="内容和商标的所有权" tabindex="-1">内容和商标的所有权 <a class="header-anchor" href="#内容和商标的所有权" aria-label="Permalink to &quot;内容和商标的所有权&quot;">​</a></h4><p>科大讯飞股份有限公司提供内容包括但不限于：非用户上传/提供的文字、软件、声音、相片、视频、图表等。所有这些内容均属于科大讯飞公司，并受版权、商标、专利和其它财产所有权法律的保护。所以，用户只能在科大讯飞股份有限公司授权下才能使用这些内容，而不能擅自复制、再造这些内容、或创造与内容有关的派生产品。</p><p>讯飞带屏音箱以及科大讯飞股份有限公司的其他标志及讯飞产品、服务的名称，均为科大讯飞讯飞股份有限公司之商标（以下简称“讯飞标识”）。未经科大讯飞的书面同意，用户不得将讯飞标识以任何方式展示或使用或作其他处理，也不得向他人表明你有权展示、使用、或其他有权处理讯飞标识的行为。</p><h4 id="法律法规责任" tabindex="-1">法律法规责任 <a class="header-anchor" href="#法律法规责任" aria-label="Permalink to &quot;法律法规责任&quot;">​</a></h4><p>如果发现或收到他人举报或投诉用户违反本协议约定的，科大讯飞股份有限公司有权不经通知随时对相关内容进行删除，并视行为情节对违规帐号处以包括但不限于警告、限制或禁止使用全部或部分功能、帐号封禁直至注销的处罚，并公告处理结果。</p><p>用户理解并同意，科大讯飞股份有限公司有权依合理判断对违反有关法律法规或本协议规定的行为进行处罚，对违法违规的任何人士采取适当的法律行动，并依据法律法规保存有关信息向有关部门报告等，用户应独自承担由此而产生的一切法律责任。</p><h2 id="协议的生效与变更" tabindex="-1">协议的生效与变更 <a class="header-anchor" href="#协议的生效与变更" aria-label="Permalink to &quot;协议的生效与变更&quot;">​</a></h2><ol><li>用户使用本服务即视为你已阅读并同意受本协议的约束。</li><li>科大讯飞股份有限公司有权在必要时修改本协议条款。你可以在相关服务页面查阅最新版本的协议条款。</li><li>本协议条款变更后，如果你继续使用讯飞带屏音箱服务，即视为你已接受修改后的协议。如果你不接受修改后的协议，可以停止使用讯飞带屏音箱服务。</li></ol><h2 id="其他" tabindex="-1">其他 <a class="header-anchor" href="#其他" aria-label="Permalink to &quot;其他&quot;">​</a></h2><ol><li>本协议签订地为中华人民共和国安徽省合肥市高新区。</li><li>本协议的成立、生效、履行、解释及纠纷解决，适用于中华人民共和国大陆地区法律（不包括冲突法）。</li><li>本协议所有条款的标题仅为阅读方便，本身并无实际涵义，不能作为本协议涵义解释的依据。</li><li>本协议条款无论因何种原因部分无效或不可执行，其余条款仍有效，对双方具有约束力。</li></ol>',42)])])}const k=i(r,[["render",t]]);export{p as __pageData,k as default};
